### Solution Code
```typescript
function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    let minEndTime = Infinity;
    for (let i = 0; i < landStartTime.length; i++) {
        for (let j = 0; j < waterStartTime.length; j++) {
            const landEnd = landStartTime[i] + landDuration[i];
            const startWater = Math.max(landEnd, waterStartTime[j]);
            const total1 = startWater + waterDuration[j];

            const waterEnd = waterStartTime[j] + waterDuration[j];
            const startLand = Math.max(waterEnd, landStartTime[i]);
            const total2 = startLand + landDuration[i];

            const candidate = Math.min(total1, total2);
            if (candidate < minEndTime) {
                minEndTime = candidate;
            }
        }
    }
    return minEndTime;
}
```

