```typescript
function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    const waterRides = waterStartTime.map((s, j) => ({ start: s, duration: waterDuration[j] }));
    const landRides = landStartTime.map((s, i) => ({ start: s, duration: landDuration[i] }));

    const waterGetter = buildMinGetter(waterRides);
    const landGetter = buildMinGetter(landRides);

    let ans = Infinity;

    for (let i = 0; i < landRides.length; i++) {
        const finishLand = landStartTime[i] + landDuration[i];
        const timeForWater = query(waterGetter, finishLand);
        if (timeForWater < ans) {
            ans = timeForWater;
        }
    }

    for (let j = 0; j < waterRides.length; j++) {
        const finishWater = waterStartTime[j] + waterDuration[j];
        const timeForLand = query(landGetter, finishWater);
        if (timeForLand < ans) {
            ans = timeForLand;
        }
    }

    return ans;
}

function buildMinGetter(rides: { start: number; duration: number; }[]): {
    sortedRides: { start: number; duration: number; total: number; }[];
    prefixMinD: number[];
    suffixMinTotal: number[];
} {
    if (rides.length === 0) {
        return {
            sortedRides: [],
            prefixMinD: [],
            suffixMinTotal: []
        };
    }
    const sortedRides = rides.slice()
        .map(ride => ({ ...ride, total: ride.start + ride.duration }))
        .sort((a, b) => a.start - b.start);
    const n = sortedRides.length;
    const prefixMinD = new Array(n);
    const suffixMinTotal = new Array(n);

    prefixMinD[0] = sortedRides[0].duration;
    for (let i = 1; i < n; i++) {
        prefixMinD[i] = Math.min(prefixMinD[i - 1], sortedRides[i].duration);
    }

    suffixMinTotal[n - 1] = sortedRides[n - 1].total;
    for (let i = n - 2; i >= 0; i--) {
        suffixMinTotal[i] = Math.min(suffixMinTotal[i + 1], sortedRides[i].total);
    }

    return {
        sortedRides,
        prefixMinD,
        suffixMinTotal
    };
}

function query(
    getter: {
        sortedRides: { start: number; duration: number; total: number; }[];
        prefixMinD: number[];
        suffixMinTotal: number[];
    },
    t: number
): number {
    const { sortedRides, prefixMinD, suffixMinTotal } = getter;
    const n = sortedRides.length;
    if (n === 0) {
        return Infinity;
    }

    let low = 0;
    let high = n - 1;
    let idx = -1;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (sortedRides[mid].start <= t) {
            idx = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    let candidate1 = Infinity;
    let candidate2 = Infinity;

    if (idx >= 0) {
        candidate1 = t + prefixMinD[idx];
    }

    if (idx + 1 < n) {
        candidate2 = suffixMinTotal[idx + 1];
    }

    return Math.min(candidate1, candidate2);
}
```

